INSERT INTO trivia_questions (company_id, question, option_a, option_b, option_c, option_d, correct_answer, category, difficulty, is_active) VALUES
  ('hd', 'What is the approximate number of stores HD operates globally as of 2024?', 'Over 2,300 stores', 'Over 1,800 stores', 'Over 3,100 stores', 'Over 4,500 stores', 'a', 'earnings', 'medium', true),
  ('hd', 'HD''s ''Warehouse'' concept emphasized which key operational advantage?', 'High markup pricing', 'Low costs through bulk purchasing and self-service', 'Premium customer service only', 'Designer showroom displays', 'b', 'earnings', 'medium', true),
  ('hd', 'What major acquisition did HD make in 2006 that expanded its supply chain?', 'Acquisition of 60 supply houses', 'Acquisition of 150 lumber yards', 'Acquisition of 200 paint stores', 'Acquisition of 100 tool rental shops', 'a', 'earnings', 'medium', true),
  ('hd', 'Which digital platform did HD launch to compete in online home improvement retail?', 'HomeDepot.com launched in 1997', 'HomeDepot.com launched in 2000', 'BuilderConnect.com launched in 1999', 'DIYHub.com launched in 2001', 'b', 'earnings', 'medium', true),
  ('hd', 'What was HD''s approximate annual revenue in fiscal year 2023?', '$120 billion', '$152 billion', '$180 billion', '$210 billion', 'b', 'earnings', 'medium', true),
  ('hd', 'HD''s ''Services'' business line includes which offerings?', 'Installation, design consultation, and tool rental', 'Only flooring installation', 'Only roofing and siding', 'Only appliance delivery', 'a', 'earnings', 'medium', true),
  ('hd', 'Which technology initiative did HD implement to enhance in-store navigation and product location?', 'Mobile app with aisle location mapping', 'RFID chips on all products', 'QR codes exclusively', 'Barcode scanning only', 'a', 'earnings', 'medium', true),
  ('hd', 'HD''s strategy to achieve omnichannel integration primarily focused on which operational goal?', 'Eliminating all physical stores', 'Seamless shopping across online, mobile, and stores', 'Focusing exclusively on e-commerce', 'Removing digital capabilities', 'b', 'earnings', 'medium', true),
  ('hd', 'What significant market expansion occurred when HD entered Canada in which year?', '1994', '1999', '2001', '2005', 'a', 'earnings', 'medium', true),
  ('hd', 'HD''s dividend history demonstrates which financial commitment to shareholders?', 'Suspended dividends since 2010', 'Consistent annual dividend increases for 10+ years', 'One-time dividend only in 2015', 'No dividends paid until 2018', 'b', 'earnings', 'medium', true),
  ('hd', 'Which strategic pivot did HD prioritize post-2020 pandemic period?', 'Reducing e-commerce capabilities', 'Accelerating digital transformation and curbside pickup', 'Closing all distribution centers', 'Eliminating professional contractor programs', 'b', 'earnings', 'medium', true);
